386	// cutPromised cuts the last part of s at the last occurrence of sep. If sep is
387	// found, the part before and after sep are returned as-is unless empty, in
388	// which case they are returned as MissingPart, which will cause
389	// [Name.IsValid] to return false.
390	func cutPromised(s, sep string) (before, after string, ok bool) {
391		before, after, ok = cutLast(s, sep)
392		if !ok {
393			return before, after, false
394		}
395		return cmp.Or(before, MissingPart), cmp.Or(after, MissingPart), true
396	}
