24	func NewLayer(r io.Reader, mediatype string) (Layer, error) {
25		blobs, err := BlobsPath("")
26		if err != nil {
27			return Layer{}, err
28		}
29	
30		temp, err := os.CreateTemp(blobs, "sha256-")
31		if err != nil {
32			return Layer{}, err
33		}
34		defer temp.Close()
35		defer os.Remove(temp.Name())
36	
37		sha256sum := sha256.New()
38		n, err := io.Copy(io.MultiWriter(temp, sha256sum), r)
39		if err != nil {
40			return Layer{}, err
41		}
42	
43		if err := temp.Close(); err != nil {
44			return Layer{}, err
45		}
46	
47		digest := fmt.Sprintf("sha256:%x", sha256sum.Sum(nil))
48		blob, err := BlobsPath(digest)
49		if err != nil {
50			return Layer{}, err
51		}
52	
53		status := "using existing layer"
54		if _, err := os.Stat(blob); err != nil {
55			status = "creating new layer"
56			if err := os.Rename(temp.Name(), blob); err != nil {
57				return Layer{}, err
58			}
59			if err := os.Chmod(blob, 0o644); err != nil {
60				return Layer{}, err
61			}
62		}
63	
64		return Layer{
65			MediaType: mediatype,
66			Digest:    digest,
67			Size:      n,
68			Status:    fmt.Sprintf("%s %s", status, digest),
69		}, nil
70	}
