    if err != nil {
        return nil, err  // Returns os.ErrNotExist if file not found
    }
    defer f.Close()

    fi, err := f.Stat()
    if err != nil {
        return nil, err
    }

    sha256sum := sha256.New()
    if err := json.NewDecoder(io.TeeReader(f, sha256sum)).Decode(&m); err != nil {
